class Solution:
    def minimumTimeToInitialState(self, word, k):
        n = len(word)
        for t in range(1, n // k + 2):
            start = t * k
            if start >= n:
                return t
            if word[start:] == word[:n - start]:
                return t
        return (n + k - 1) // k

