class Solution:
    def minimumTimeToInitialState(self, word, k):
        n = len(word)
        # KMP prefix function
        fail = [0] * n
        j = 0
        for i in range(1, n):
            while j and word[i] != word[j]:
                j = fail[j-1]
            if word[i] == word[j]:
                j += 1
            fail[i] = j
        # Positions where word[p:] is a prefix of word
        valid = set()
        p = fail[n-1]
        while p:
            valid.add(n - p)
            p = fail[p-1]
        valid.add(n)  # fully consumed
        for t in range(1, n // k + 2):
            if t * k in valid or t * k >= n:
                return t
        return (n + k - 1) // k

