var minimumTimeToInitialState = function(word, k) {
    const n = word.length;
    const fail = new Int32Array(n);
    let j = 0;
    for (let i = 1; i < n; i++) {
        while (j && word[i] !== word[j]) j = fail[j-1];
        if (word[i] === word[j]) j++;
        fail[i] = j;
    }
    const valid = new Set();
    let p = fail[n-1];
    while (p) { valid.add(n - p); p = fail[p-1]; }
    valid.add(n);
    for (let t = 1; ; t++) {
        const s = t * k;
        if (s >= n || valid.has(s)) return t;
    }
};
